var rotationPolicy = new KeyRotationPolicy
{
    LifetimeActions =
    {
        new KeyLifetimeAction
        {
            Action = KeyRotationAction.Notify,
            TimeBeforeExpiry = TimeSpan.FromDays(30)
        }
    }
};

await keyClient.UpdateKeyRotationPolicyAsync("my-key", rotationPolicy);
